@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState PersistState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSubscription;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe so that during prerender we persist the data into the page payload.
        _persistSubscription = PersistState.RegisterOnPersisting(PersistData);

        // If the data was already persisted (i.e. we're reconnecting after prerender),
        // restore it instead of calling the service again.
        if (PersistState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        PersistState.PersistAsJson("equipment", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistSubscription.Dispose();
    }
}

